def v(key, label, label_vi, typ, fmt, example, required, source, used_in, description, validation=None, enum_values=None):
    """Helper to build a variable dict."""
    obj = {
        "key": key,
        "label": label,
        "label_vi": label_vi,
        "type": typ,
        "format": fmt,
        "example": example,
        "required": required,
        "source": source,
        "used_in": used_in,
        "description": description
    }
    if validation is not None:
        obj["validation"] = validation
    if enum_values is not None:
        obj["enum_values"] = enum_values
    return obj

