# For the remaining categories, I'll use a more compact approach
def add_category(cat_key, label, label_vi, desc, var_list):
    """Add a category with variables from a list of tuples."""
    variables = {}
    for item in var_list:
        if len(item) == 10:
            key, lb, lv, tp, fm, ex, rq, sr, ui, ds = item
            variables[key] = v(key, lb, lv, tp, fm, ex, rq, sr, ui, ds)
        elif len(item) == 11:
            key, lb, lv, tp, fm, ex, rq, sr, ui, ds, vd = item
            variables[key] = v(key, lb, lv, tp, fm, ex, rq, sr, ui, ds, vd)
        elif len(item) == 12:
            key, lb, lv, tp, fm, ex, rq, sr, ui, ds, vd, ev = item
            variables[key] = v(key, lb, lv, tp, fm, ex, rq, sr, ui, ds, vd, ev)
    data["categories"][cat_key] = {
        "label": label,
        "label_vi": label_vi,
        "description": desc,
        "variables": variables
    }

